import React, { useEffect, useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [order, setOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);
  const [editingId, setEditingId] = useState(null);

  /* ================= FETCH PARENT LINKS ================= */
  const fetchLinks = async () => {
    try {
      const res = await fetch(API);
      const data = await res.json();

      // Only Parent Links
      const parentLinks = data
        .filter((link) => !link.parent)
        .sort((a, b) => a.order - b.order);

      setLinks(parentLinks);
    } catch (error) {
      console.error("Fetch Error:", error);
    }
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  /* ================= SUBMIT ================= */
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    try {
      if (editingId) {
        await fetch(`${API}/${editingId}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name,
            order,
            isActive,
            parent: null,
          }),
        });
      } else {
        await fetch(API, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name,
            order,
            isActive,
            parent: null,
          }),
        });
      }

      resetForm();
      fetchLinks();
    } catch (error) {
      console.error("Submit Error:", error);
    }
  };

  /* ================= EDIT ================= */
  const handleEdit = (link) => {
    setName(link.name);
    setOrder(link.order);
    setIsActive(link.isActive);
    setEditingId(link._id);
  };

  /* ================= DELETE ================= */
  const handleDelete = async (id) => {
    try {
      await fetch(`${API}/${id}`, { method: "DELETE" });
      fetchLinks();
    } catch (error) {
      console.error("Delete Error:", error);
    }
  };

  const resetForm = () => {
    setName("");
    setOrder(0);
    setIsActive(true);
    setEditingId(null);
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        {/* HEADER */}
        <div className={design.headerWrapper}>
          <div>
            <h1 className={design.title}>Parent Navigation Links</h1>
            <p className={design.subtitle}>
              Manage main menu items only.
            </p>
          </div>
        </div>

        <div className={design.card}>
          {/* FORM */}
          <form onSubmit={handleSubmit} className={design.formSection}>
            <input
              type="text"
              placeholder="Link Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={design.input}
            />

            <input
              type="number"
              placeholder="Order"
              value={order}
              onChange={(e) => setOrder(Number(e.target.value))}
              className={design.input}
            />

            <select
              value={isActive}
              onChange={(e) => setIsActive(e.target.value === "true")}
              className={design.select}
            >
              <option value="true">Active</option>
              <option value="false">Inactive</option>
            </select>

            <motion.button
              whileTap={{ scale: 0.95 }}
              type="submit"
              className={design.buttonPrimary}
            >
              <Plus size={16} />
              {editingId ? "Update" : "Add"}
            </motion.button>
          </form>

          {/* TABLE */}
          <div className={design.tableWrapper}>
            <div className={design.tableHeader}>
              <div>Name</div>
              <div>Status</div>
              <div>Order</div>
              <div className="text-right">Actions</div>
            </div>

            <AnimatePresence>
              {links.length === 0 ? (
                <div className={design.emptyState}>
                  No parent links created yet.
                </div>
              ) : (
                links.map((link) => (
                  <motion.div
                    key={link._id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    transition={{ duration: 0.2 }}
                    className={design.tableRow}
                  >
                    <div className="font-medium text-slate-800">
                      {link.name}
                    </div>

                    <div>
                      <span
                        className={
                          link.isActive
                            ? design.badgeActive
                            : design.badgeInactive
                        }
                      >
                        {link.isActive ? "Active" : "Inactive"}
                      </span>
                    </div>

                    <div>{link.order}</div>

                    <div className="flex justify-end gap-5">
                      <button
                        onClick={() => handleEdit(link)}
                        className="text-slate-500 hover:text-indigo-600 transition"
                      >
                        <Pencil size={18} />
                      </button>

                      <button
                        onClick={() => handleDelete(link._id)}
                        className="text-slate-500 hover:text-red-600 transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </motion.div>
                ))
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
